const prepared = $('�nderungsart vorbereiten').first().json;
const form = $('MDB �nderung final pr�fen').first().json;
const config = $('Config - WF4').first().json;
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);

function clean(v) {
  return String(v ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function norm(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/�/g, 'ae')
    .replace(/�/g, 'oe')
    .replace(/�/g, 'ue')
    .replace(/�/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function mdbNorm(v) {
  const s = clean(v).replace(',', '.');
  return /^\d+\.0+$/.test(s) ? String(parseInt(s, 10)) : s;
}

function iso(v) {
  const raw = clean(v);
  const d = raw ? new Date(raw) : new Date();

  if (Number.isNaN(d.getTime())) {
    throw new Error('G�ltig ab UTC ist kein valides Datum/Zeitformat: ' + raw);
  }

  return d.toISOString();
}

function stamp(v) {
  return clean(v)
    .replace(/[-:]/g, '')
    .replace(/\.\d+Z$/, 'Z');
}

function psid(machineId, mdb, productKey, validFromUtc) {
  return `PS_${clean(machineId)}_${mdbNorm(mdb)}_${clean(productKey)}_${stamp(validFromUtc)}`;
}

function first(...vals) {
  return vals.map(clean).find(v => v !== '') || '';
}

function isActive(row) {
  const active = clean(row.active).toUpperCase();
  const validTo = clean(row.valid_to_datetime || row.valid_to);

  return ['TRUE', '1', 'JA', 'YES', 'AKTIV', 'ACTIVE'].includes(active) && !validTo;
}

function hasSlotData(row) {
  return !!(
    clean(row.product_slot_id) ||
    clean(row.machine_id) ||
    clean(row.mdb_code) ||
    clean(row.valid_from_datetime) ||
    clean(row.valid_from)
  );
}

function productName(row) {
  return first(
    row.internal_product_name,
    row.nayax_product_name,
    row.product_key
  );
}

const now = new Date().toISOString();

const machineId = (() => {
  const raw = clean(prepared.machine_id || config.default_machine_id);
  const asNum = Number(raw);
  return Number.isFinite(asNum) ? String(Math.round(asNum)) : raw;
})();
const oldMdb = mdbNorm(form['MDB-Code alt'] || prepared.expected_mdb_code);
const newMdb = mdbNorm(form['MDB-Code neu'] || prepared.actual_mdb_code || prepared.parsed_mdb_code);
const validFromUtc = iso(form['G�ltig ab UTC'] || prepared.default_valid_from_utc);
const note = clean(form.Notiz);

const changeTypeDe = clean(prepared.change_type_de);
const changeTypeInternal = clean(prepared.change_type_internal);

if (!changeTypeInternal || changeTypeInternal === 'UNKNOWN') {
  throw new Error('Unbekannte �nderungsart. Bitte im vorherigen Formular eine g�ltige �nderungsart w�hlen.');
}

const selected = {
  product_key: clean(prepared.selected_product_key),
  internal_product_name: clean(prepared.selected_internal_product_name),
  nayax_product_name: clean(prepared.selected_nayax_product_name),
  sale_price_eur: clean(prepared.parsed_sale_price_eur)
};

const isRejected =
  norm(form.Freigabe) !== 'ja' ||
  prepared.aborted === true;

const replaceTargetSlot = norm(form['Zielslot ersetzen']) === 'ja';

const closeRows = [];
const newRows = [];
const baseRowUpdates = [];
const warningRows = [];
const logRows = [];

const selectedProductKey = clean(selected.product_key);
const selectedName = first(
  selected.internal_product_name,
  selected.nayax_product_name,
  selected.product_key
);

const changeId = `CHG_${machineId}_${oldMdb || 'NA'}_${newMdb || 'NA'}_${selectedProductKey || 'NO_PRODUCT'}_${stamp(validFromUtc)}`;

function warning(type, severity, message, productKey = '') {
  warningRows.push({
    created_at: now,
    type,
    severity,
    machine_id: machineId,
    product_key: productKey || selectedProductKey,
    nayax_product_name: selectedName,
    message,
    resolved: 'FALSE',
    change_id: changeId
  });
}

if (isRejected) {
  logRows.push({
    change_id: changeId,
    changed_at_utc: now,
    source: prepared.source,
    detected_reason: prepared.detected_reason,
    machine_id: machineId,
    old_mdb_code: oldMdb,
    new_mdb_code: newMdb,
    old_product_key: '',
    old_product_name: '',
    new_product_key: selectedProductKey,
    new_product_name: selectedName,
    change_type_de: changeTypeDe,
    change_type_internal: changeTypeInternal,
    valid_from_utc: validFromUtc,
    status: 'abgelehnt',
    action_required: 'FALSE',
    notes: note || 'Im Formular abgelehnt.'
  });

  return [{
    json: {
      closeRows,
      newRows,
      baseRowUpdates,
      warningRows,
      logRows,
      summary: {
        status: 'abgelehnt',
        change_id: changeId
      }
    }
  }];
}

if (!newMdb && ['REPLACE_PRODUCT_IN_SLOT', 'MOVE_PRODUCT', 'ADD_ADDITIONAL_SLOT'].includes(changeTypeInternal)) {
  throw new Error('MDB-Code neu fehlt.');
}

if (!selectedProductKey && !['REMOVE_PRODUCT_FROM_SLOT', 'STOCK_CORRECTION'].includes(changeTypeInternal)) {
  throw new Error('Kein Produkt ausgew�hlt.');
}

const activeRows = products.filter(p =>
  clean(p.machine_id) === machineId &&
  isActive(p)
);

const activeOnNew = activeRows.filter(p =>
  mdbNorm(p.mdb_code) === newMdb
);

const activeOnOld = oldMdb
  ? activeRows.filter(p => mdbNorm(p.mdb_code) === oldMdb)
  : [];

const activeSameProduct = activeRows.filter(p =>
  clean(p.product_key) === selectedProductKey
);

const exactActive = activeRows.filter(p =>
  mdbNorm(p.mdb_code) === newMdb &&
  clean(p.product_key) === selectedProductKey
);

const baseRows = products.filter(p =>
  clean(p.product_key) === selectedProductKey &&
  !hasSlotData(p)
);

function close(row, reason) {
  return {
    product_slot_id: clean(row.product_slot_id),
    product_key: clean(row.product_key),
    machine_id: clean(row.machine_id || machineId),
    mdb_code: mdbNorm(row.mdb_code),
    active: 'FALSE',
    valid_from_datetime: clean(row.valid_from_datetime || row.valid_from || validFromUtc),
    valid_from: clean(row.valid_from || row.valid_from_datetime || validFromUtc),
    valid_to_datetime: validFromUtc,
    valid_to: validFromUtc,
    last_change_id: changeId,
    notes: [
      clean(row.notes),
      reason,
      note
    ].filter(Boolean).join(' | ')
  };
}

function slotFields(product, mdb) {
  return {
    product_slot_id: psid(machineId, mdb, product.product_key, validFromUtc),
    product_key: product.product_key,
    machine_id: machineId,
    mdb_code: mdbNorm(mdb),
    nayax_product_name: first(product.nayax_product_name, product.internal_product_name),
    internal_product_name: first(product.internal_product_name, product.nayax_product_name),
    sale_price_eur: clean(product.sale_price_eur),
    valid_from_datetime: validFromUtc,
    valid_from: validFromUtc,
    valid_to_datetime: '',
    valid_to: '',
    active: 'TRUE',
    replenishment_status: 'aktiv',
    min_stock: clean(form.Mindestbestand),
    target_stock: clean(form.Zielbestand),
    current_machine_qty: clean(form['Aktueller Maschinenbestand nach �nderung']),
    machine_capacity: clean(form['Slot-Kapazit�t']),
    stock_source: 'WF4_MDB_Produktwechsel',
    last_change_id: changeId,
    notes: note
  };
}

function setSlot(product, mdb) {
  if (exactActive.length) {
    warning(
      'WF4_SLOT_ALREADY_ACTIVE',
      'info',
      `Aktive Slotzeile existiert bereits fuer machine_id=${machineId}, mdb=${mdbNorm(mdb)}, product_key=${selectedProductKey}. Es wurde keine neue Produktzeile erzeugt.`
    );
    return;
  }

  if (baseRows.length > 1) {
    warning(
      'WF4_DUPLICATE_BASE_PRODUCT_ROWS',
      'error',
      `Mehrere slotlose WF2-Produktzeilen fuer product_key=${selectedProductKey} gefunden. Bitte zuerst bereinigen; WF4 erzeugt keine weitere Dublette.`
    );
    return;
  }

  const fields = slotFields(product, mdb);

  if (baseRows.length === 1) {
    baseRowUpdates.push(fields);
  } else {
    newRows.push(fields);
  }
}

// 1. Produkt auf anderen MDB-Slot umziehen
if (changeTypeInternal === 'MOVE_PRODUCT') {
  const targetBlockers = activeOnNew.filter(r =>
    clean(r.product_key) !== selectedProductKey
  );

  if (targetBlockers.length && !replaceTargetSlot) {
    warning(
      'WF4_TARGET_SLOT_OCCUPIED_NOT_REPLACED',
      'error',
      `MDB ${newMdb} ist bereits belegt mit ${targetBlockers.map(productName).join(', ')}. Zielslot ersetzen steht auf NEIN.`
    );
  } else {
    // Zielslot freimachen, wenn dort ein anderes Produkt aktiv ist.
    for (const r of targetBlockers) {
      closeRows.push(close(
        r,
        `WF4: Zielslot MDB ${newMdb} wurde fuer ${selectedProductKey} freigemacht.`
      ));
    }

    // Alte aktive Slots desselben Produkts schlie�en.
    // Wenn oldMdb leer ist, alle Slots au�er Ziel-MDB schlie�en.
    const rowsToClose = oldMdb
      ? activeSameProduct.filter(r => mdbNorm(r.mdb_code) === oldMdb)
      : activeSameProduct.filter(r => mdbNorm(r.mdb_code) !== newMdb);

    for (const r of rowsToClose) {
      closeRows.push(close(
        r,
        'WF4: Produkt auf anderen MDB-Slot umgezogen.'
      ));
    }

    setSlot(selected, newMdb);
  }
}

// 2. Produkt im Slot austauschen
if (changeTypeInternal === 'REPLACE_PRODUCT_IN_SLOT') {
  const targetBlockers = activeOnNew.filter(r =>
    clean(r.product_key) !== selectedProductKey
  );

  if (targetBlockers.length && !replaceTargetSlot) {
    warning(
      'WF4_TARGET_SLOT_OCCUPIED_NOT_REPLACED',
      'error',
      `MDB ${newMdb} ist bereits belegt mit ${targetBlockers.map(productName).join(', ')}. Zielslot ersetzen steht auf NEIN.`
    );
  } else {
    for (const r of targetBlockers) {
      closeRows.push(close(
        r,
        'WF4: Produkt im Slot ausgetauscht.'
      ));
    }

    setSlot(selected, newMdb);
  }
}

// 3. Produkt zus�tzlich auf weiteren Slot legen
if (changeTypeInternal === 'ADD_ADDITIONAL_SLOT') {
  const blockers = activeOnNew.filter(r =>
    clean(r.product_key) !== selectedProductKey
  );

  if (blockers.length) {
    warning(
      'WF4_TARGET_SLOT_OCCUPIED',
      'error',
      `MDB ${newMdb} ist bereits aktiv belegt. Fuer zus�tzlichen Slot bitte anderen MDB-Code w�hlen oder Produkttausch verwenden.`
    );
  } else {
    setSlot(selected, newMdb);
  }
}

// 4. Produkt aus Slot entfernen
if (changeTypeInternal === 'REMOVE_PRODUCT_FROM_SLOT') {
  const rows = activeOnNew.length ? activeOnNew : activeOnOld;

  for (const r of rows) {
    closeRows.push(close(
      r,
      'WF4: Produkt aus Slot entfernt.'
    ));
  }
}

// 5. Nur Stammdaten korrigieren
if (changeTypeInternal === 'CORRECT_METADATA') {
  warning(
    'WF4_METADATA_CORRECTION_NOT_AUTOMATED',
    'warning',
    'Nur Stammdaten korrigieren gew�hlt. Diese Version protokolliert nur.'
  );
}

// 6. Bestand korrigieren ohne Produktwechsel
if (changeTypeInternal === 'STOCK_CORRECTION') {
  warning(
    'WF4_STOCK_CORRECTION_REQUESTED',
    'action_required',
    'Bestand korrigieren ohne Produktwechsel gew�hlt. Bitte Bestandskorrekturworkflow verwenden.'
  );
}

// Sicherheitspr�fung: Alte Zeilen ohne product_slot_id nicht automatisch schlie�en.
for (const r of closeRows) {
  if (!clean(r.product_slot_id)) {
    warning(
      'MISSING_PRODUCT_SLOT_ID',
      'error',
      `Alte Produktzeile konnte nicht sicher geschlossen werden, weil product_slot_id fehlt. product_key=${r.product_key}, mdb=${r.mdb_code}`,
      r.product_key
    );
  }
}

const hasError = warningRows.some(w =>
  clean(w.severity) === 'error'
);

if (hasError) {
  newRows.length = 0;
  baseRowUpdates.length = 0;
}

const realChangesCount =
  closeRows.length +
  newRows.length +
  baseRowUpdates.length;

let finalStatus = hasError ? 'mit_fehler' : 'verarbeitet';
let actionRequired = warningRows.length ? 'TRUE' : 'FALSE';

if (
  !hasError &&
  realChangesCount === 0 &&
  !['CORRECT_METADATA', 'STOCK_CORRECTION'].includes(changeTypeInternal)
) {
  finalStatus = 'aktion_erforderlich';
  actionRequired = 'TRUE';

  warning(
    'WF4_NO_REAL_CHANGE_WRITTEN',
    'action_required',
    'WF4 hat keine echte Produkt-/Slot�nderung geschrieben. Bitte Eingaben pr�fen.'
  );
}

logRows.push({
  change_id: changeId,
  changed_at_utc: now,
  source: prepared.source,
  detected_reason: prepared.detected_reason,
  machine_id: machineId,
  old_mdb_code: oldMdb,
  new_mdb_code: newMdb,
  old_product_key: closeRows.map(r => r.product_key).join('; '),
  old_product_name: closeRows.map(r => productName(r)).join('; '),
  new_product_key: selectedProductKey,
  new_product_name: selectedName,
  change_type_de: changeTypeDe,
  change_type_internal: changeTypeInternal,
  valid_from_utc: validFromUtc,
  status: finalStatus,
  action_required: actionRequired,
  notes: note
});

return [{
  json: {
    closeRows,
    newRows,
    baseRowUpdates,
    warningRows,
    logRows,
    summary: {
      status: finalStatus,
      change_id: changeId,
      close_rows: closeRows.length,
      new_rows: newRows.length,
      base_row_updates: baseRowUpdates.length,
      warnings: warningRows.length
    }
  }
}];

const config = $('Config - WF4').first().json;
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);
const aliases = $items('Google Sheets - Produkt_Aliase lesen').map(i => i.json);

let input = {};
try {
  input = $('Form Trigger - Nayax Name eingeben').first().json;
} catch (e) {
  input = {};
}

try {
  const execInput = $('Execute Workflow Trigger - aus Verkaufsworkflow').first().json;
  if (Object.keys(execInput || {}).length) input = execInput;
} catch (e) {}

function clean(v) {
  return String(v ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalize(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/�/g, 'ae')
    .replace(/�/g, 'oe')
    .replace(/�/g, 'ue')
    .replace(/�/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function tokens(v) {
  const n = normalize(v);
  return [...new Set((n.match(/[a-z]+|[0-9]+/g) || []).filter(t => t.length >= 2))];
}

function parseNayaxName(raw) {
  const text = clean(raw);

  // Beispiel: "Snickers Cream Peanut Butter(12 = 1.00)"
  const m = text.match(/^(.*?)\s*\((\d+)\s*=\s*([0-9]+(?:[.,][0-9]+)?)\)\s*$/);

  if (!m) {
    return {
      label: text,
      mdb_code: '',
      sale_price_eur: ''
    };
  }

  return {
    label: clean(m[1]),
    mdb_code: clean(m[2]),
    sale_price_eur: clean(m[3]).replace(',', '.')
  };
}

function isActive(v) {
  const value = clean(v).toUpperCase();
  return value === 'TRUE' || value === 'AKTIV' || value === 'ACTIVE' || value === 'JA' || value === '1';
}

function hasSlotData(p) {
  return clean(p.machine_id) || clean(p.mdb_code) || clean(p.product_slot_id);
}

function scoreProduct(product, queryLabel, parsedMdb, suggestedProductKey) {
  const productKey = clean(product.product_key);
  const internalName = clean(product.internal_product_name);
  const nayaxName = clean(product.nayax_product_name);
  const mdbCode = clean(product.mdb_code);
  const machineId = clean(product.machine_id);

  const queryNorm = normalize(queryLabel);
  const productText = [
    productKey,
    internalName,
    nayaxName,
    mdbCode,
    machineId
  ].join(' ');

  const productNorm = normalize(productText);

  let score = 0;

  if (suggestedProductKey && productKey === suggestedProductKey) score += 100;

  if (queryNorm && normalize(nayaxName) === queryNorm) score += 95;
  if (queryNorm && normalize(internalName) === queryNorm) score += 90;
  if (queryNorm && normalize(productKey) === queryNorm) score += 90;

  if (queryNorm && normalize(nayaxName).includes(queryNorm)) score += 70;
  if (queryNorm && normalize(internalName).includes(queryNorm)) score += 65;
  if (queryNorm && productNorm.includes(queryNorm)) score += 55;

  const queryTokens = tokens(queryLabel);
  const productTokens = tokens(productText);
  const overlap = queryTokens.filter(t => productTokens.includes(t));

  score += overlap.length * 12;

  if (parsedMdb && mdbCode === parsedMdb) score += 15;
  if (isActive(product.active)) score += 5;

  return Math.min(score, 99);
}

function scoreAlias(alias, queryLabel) {
  const aliasName = clean(alias.alias_name || alias.source_item || alias.invoice_item_example);
  const q = normalize(queryLabel);
  const a = normalize(aliasName);

  if (!q || !a) return 0;
  if (a === q) return 90;
  if (a.includes(q) || q.includes(a)) return 70;

  const qTokens = tokens(queryLabel);
  const aTokens = tokens(aliasName);
  const overlap = qTokens.filter(t => aTokens.includes(t));

  return overlap.length * 15;
}

const rawSearch = clean(
  input['Nayax Produktname oder Suchbegriff'] ||
  input.nayax_product_name ||
  input.raw_product_name ||
  input.product_name ||
  input.search ||
  ''
);

const parsed = parseNayaxName(rawSearch);

const searchLabel = clean(
  input.product_label ||
  parsed.label ||
  rawSearch
);

const machineId = clean(input.machine_id || config.default_machine_id || '');
const suggestedProductKey = clean(input.product_key || input.suggested_product_key || '');
const expectedMdbCode = clean(input.expected_mdb_code || input.old_mdb_code || '');
const actualMdbCode = clean(input.actual_mdb_code || input.new_mdb_code || input.mdb_code || parsed.mdb_code || '');
const settlementDatetimeGmt = clean(input.settlement_datetime_gmt || input.sale_datetime_utc || '');
const detectedReason = clean(input.detected_reason || '');
const source = clean(input.source || 'manual_or_sales_workflow');

if (!searchLabel && !suggestedProductKey) {
  throw new Error('Kein Suchbegriff und kein product_key vorhanden.');
}

// Alias-Treffer vorbereiten
const aliasScores = aliases
  .map(a => ({
    alias: a,
    score: scoreAlias(a, searchLabel),
    product_key: clean(a.product_key)
  }))
  .filter(a => a.score > 0 && a.product_key);

const aliasBoostByProductKey = new Map();

for (const a of aliasScores) {
  const current = aliasBoostByProductKey.get(a.product_key) || 0;
  aliasBoostByProductKey.set(a.product_key, Math.max(current, a.score));
}

// Produkte ranken
const rankedRaw = products
  .filter(p => clean(p.product_key))
  .map(p => {
    const productKey = clean(p.product_key);
    let score = scoreProduct(p, searchLabel, actualMdbCode || expectedMdbCode || parsed.mdb_code, suggestedProductKey);

    const aliasBoost = aliasBoostByProductKey.get(productKey) || 0;
    if (aliasBoost) score += Math.min(aliasBoost, 80);

    return {
      product: p,
      score: Math.min(score, 99)
    };
  })
  .filter(x => x.score >= Number(config.min_candidate_score || 35))
  .sort((a, b) => b.score - a.score);

// Deduplizieren nach product_key.
// Bei mehreren Zeilen desselben product_key bevorzugen:
// 1. aktive Slotzeile
// 2. Zeile mit Slotdaten
// 3. h�here Score-Zeile
const byKey = new Map();

for (const item of rankedRaw) {
  const key = clean(item.product.product_key);

  if (!byKey.has(key)) {
    byKey.set(key, item);
    continue;
  }

  const current = byKey.get(key);

  const itemActive = isActive(item.product.active);
  const currentActive = isActive(current.product.active);

  const itemHasSlot = hasSlotData(item.product);
  const currentHasSlot = hasSlotData(current.product);

  let replace = false;

  if (itemActive && !currentActive) replace = true;
  else if (itemActive === currentActive && itemHasSlot && !currentHasSlot) replace = true;
  else if (
    itemActive === currentActive &&
    itemHasSlot === currentHasSlot &&
    item.score > current.score
  ) replace = true;

  if (replace) byKey.set(key, item);
}

const ranked = [...byKey.values()]
  .sort((a, b) => b.score - a.score)
  .slice(0, 5);

if (!ranked.length) {
  return [{
    json: {
      source,
      detected_reason: detectedReason,
      machine_id: machineId,
      search_raw: rawSearch,
      search_label: searchLabel,
      parsed_mdb_code: parsed.mdb_code,
      parsed_sale_price_eur: parsed.sale_price_eur,
      expected_mdb_code: expectedMdbCode,
      actual_mdb_code: actualMdbCode,
      settlement_datetime_gmt: settlementDatetimeGmt,
      candidates: [],
      form_info: [
        'Keine Produktkandidaten gefunden.',
        '',
        `Suchbegriff: ${searchLabel || rawSearch}`,
        `Maschine: ${machineId || '(leer)'}`,
        `MDB aus Nayax/ProductName: ${parsed.mdb_code || '(nicht erkannt)'}`,
        '',
        'Bitte Produkt zuerst �ber Rechnung/WF2 als Produktstamm anlegen oder Suchbegriff genauer eingeben.'
      ].join('\n')
    }
  }];
}

const activeRows = products.filter(p =>
  (!machineId || clean(p.machine_id) === machineId) &&
  isActive(p.active)
);

const candidates = ranked.map((x, idx) => {
  const p = x.product;
  const productKey = clean(p.product_key);

  const activeSlots = activeRows
    .filter(r => clean(r.product_key) === productKey)
    .map(r => clean(r.mdb_code))
    .filter(Boolean);

  return {
    number: String(idx + 1),
    score: x.score,
    product_key: productKey,
    internal_product_name: clean(p.internal_product_name),
    nayax_product_name: clean(p.nayax_product_name),
    mdb_code: clean(p.mdb_code),
    machine_id: clean(p.machine_id),
    product_slot_id: clean(p.product_slot_id),
    active: isActive(p.active) ? 'TRUE' : clean(p.active),
    sale_price_eur: clean(p.sale_price_eur),
    active_slots: [...new Set(activeSlots)].join(', ')
  };
});

