    alias: a,
    score: scoreAlias(a, searchLabel),
    product_key: clean(a.product_key)
  }))
  .filter(a => a.score > 0 && a.product_key);

const aliasBoostByProductKey = new Map();

for (const a of aliasScores) {
  const current = aliasBoostByProductKey.get(a.product_key) || 0;
  aliasBoostByProductKey.set(a.product_key, Math.max(current, a.score));
}

// Produkte ranken
const rankedRaw = products
  .filter(p => clean(p.product_key))
  .map(p => {
    const productKey = clean(p.product_key);
    let score = scoreProduct(p, searchLabel, actualMdbCode || expectedMdbCode || parsed.mdb_code, suggestedProductKey);

    const aliasBoost = aliasBoostByProductKey.get(productKey) || 0;
    if (aliasBoost) score += Math.min(aliasBoost, 80);

    return {
      product: p,
      score: Math.min(score, 99)
    };
  })
  .filter(x => x.score >= Number(config.min_candidate_score || 35))
  .sort((a, b) => b.score - a.score);

// Deduplizieren nach product_key.
// Bei mehreren Zeilen desselben product_key bevorzugen:
// 1. aktive Slotzeile
// 2. Zeile mit Slotdaten
// 3. h�here Score-Zeile
const byKey = new Map();

for (const item of rankedRaw) {
  const key = clean(item.product.product_key);

  if (!byKey.has(key)) {
    byKey.set(key, item);
    continue;
  }

  const current = byKey.get(key);

  const itemActive = isActive(item.product.active);
  const currentActive = isActive(current.product.active);

  const itemHasSlot = hasSlotData(item.product);
  const currentHasSlot = hasSlotData(current.product);

  let replace = false;

  if (itemActive && !currentActive) replace = true;
  else if (itemActive === currentActive && itemHasSlot && !currentHasSlot) replace = true;
  else if (
    itemActive === currentActive &&
    itemHasSlot === currentHasSlot &&
    item.score > current.score
  ) replace = true;

  if (replace) byKey.set(key, item);
}

const ranked = [...byKey.values()]
