const source = $input.first().json;
const batchRunId = "wf4_" + new Date().toISOString().slice(0, 10);

function clean(value) {
  return String(value ?? "").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
}

function num(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

function boolActive(value) {
  return ["TRUE", "1", "JA", "YES", "AKTIV", "ACTIVE"].includes(clean(value).toUpperCase());
}

function slotEvent(row) {
  const data = {
    product_slot_key: clean(row.product_slot_id),
    machine_key: clean(row.machine_id),
    mdb_code: num(row.mdb_code),
    product_key: clean(row.product_key),
    valid_from: clean(row.valid_from_datetime || row.valid_from),
    valid_to: clean(row.valid_to_datetime || row.valid_to) || null,
    active: boolActive(row.active),
    current_machine_qty: num(row.current_machine_qty) ?? 0,
    target_stock: num(row.target_stock),
    machine_capacity: num(row.machine_capacity),
    notes: clean(row.notes),
  };
  return { json: { event_type: "slot_assignment", batch_run_id: batchRunId, data } };
}

return [
  ...(source.closeRows || []),
  ...(source.newRows || []),
  ...(source.baseRowUpdates || []),
]
  .filter((row) => clean(row.product_slot_id) && clean(row.machine_id) && clean(row.product_key))
  .map(slotEvent);
